begin;
create table callora.api_keys (organization_id uuid not null,id uuid not null,name text not null,key_prefix text not null,key_hash bytea not null,scopes text[] not null,created_by_user_id uuid not null,created_at timestamptz not null default statement_timestamp(),last_used_at timestamptz,revoked_at timestamptz,primary key(organization_id,id),unique(key_prefix),foreign key(organization_id,created_by_user_id) references callora.users(organization_id,id),constraint api_keys_hash_check check(octet_length(key_hash)=32),constraint api_keys_scopes_check check(cardinality(scopes)>0));
create index api_keys_creator_idx on callora.api_keys(organization_id,created_by_user_id);
create table callora.webhook_endpoints (organization_id uuid not null,id uuid not null,url text not null,secret_ciphertext bytea not null,events text[] not null,status text not null default 'active',created_at timestamptz not null default statement_timestamp(),updated_at timestamptz not null default statement_timestamp(),primary key(organization_id,id),constraint webhook_endpoint_status_check check(status in('active','paused','revoked')),constraint webhook_endpoint_https_check check(url~'^https://'));
create table callora.webhook_deliveries (organization_id uuid not null,id uuid not null,endpoint_id uuid not null,event_id uuid not null,event_type text not null,payload jsonb not null,status text not null default 'queued',attempt_count smallint not null default 0,next_attempt_at timestamptz not null default statement_timestamp(),response_status integer,last_error_code text,created_at timestamptz not null default statement_timestamp(),delivered_at timestamptz,primary key(organization_id,id),unique(organization_id,endpoint_id,event_id),foreign key(organization_id,endpoint_id) references callora.webhook_endpoints(organization_id,id),constraint webhook_delivery_attempt_check check(attempt_count between 0 and 8));
create index webhook_deliveries_due_idx on callora.webhook_deliveries(organization_id,status,next_attempt_at) where status='queued';
create table callora.connector_accounts (organization_id uuid not null,id uuid not null,kind text not null,environment text not null,status text not null,credentials_ciphertext bytea not null,cursor jsonb not null default '{}'::jsonb,created_at timestamptz not null default statement_timestamp(),updated_at timestamptz not null default statement_timestamp(),primary key(organization_id,id),constraint connector_kind_check check(kind in('google_sheets','generic_lead_source')),constraint connector_environment_check check(environment in('sandbox','production')),constraint connector_status_check check(status in('active','error','revoked')));
create table callora.connector_runs (organization_id uuid not null,id uuid not null,connector_account_id uuid not null,idempotency_key text not null,status text not null,attempt_count smallint not null default 0,records_processed integer not null default 0,error_code text,created_at timestamptz not null default statement_timestamp(),completed_at timestamptz,primary key(organization_id,id),unique(organization_id,connector_account_id,idempotency_key),foreign key(organization_id,connector_account_id) references callora.connector_accounts(organization_id,id));
create index connector_runs_account_idx on callora.connector_runs(organization_id,connector_account_id,created_at desc);
create table callora.subscriptions (organization_id uuid not null,id uuid not null,plan_key text not null,status text not null,provider_customer_id text,provider_subscription_id text,seat_limit integer not null,storage_limit_bytes bigint not null,api_requests_per_minute integer not null,trial_ends_at timestamptz,grace_ends_at timestamptz,current_period_ends_at timestamptz,updated_at timestamptz not null default statement_timestamp(),primary key(organization_id,id),unique(organization_id),constraint subscription_status_check check(status in('trialing','active','past_due','canceled')),constraint subscription_limits_check check(seat_limit>0 and storage_limit_bytes>0 and api_requests_per_minute>0));
create table callora.billing_events (organization_id uuid not null,id uuid not null,provider_event_id text not null,event_type text not null,payload_fingerprint bytea not null,processed_at timestamptz not null default statement_timestamp(),primary key(organization_id,id),unique(provider_event_id),constraint billing_fingerprint_check check(octet_length(payload_fingerprint)=32));
create table callora.invoices (organization_id uuid not null,id uuid not null,provider_invoice_id text not null,status text not null,currency text not null,amount_due bigint not null,hosted_invoice_url text,issued_at timestamptz not null,paid_at timestamptz,primary key(organization_id,id),unique(provider_invoice_id),constraint invoice_amount_check check(amount_due>=0));
alter table callora.api_keys enable row level security; alter table callora.api_keys force row level security; create policy api_keys_tenant on callora.api_keys using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.webhook_endpoints enable row level security; alter table callora.webhook_endpoints force row level security; create policy webhook_endpoints_tenant on callora.webhook_endpoints using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.webhook_deliveries enable row level security; alter table callora.webhook_deliveries force row level security; create policy webhook_deliveries_tenant on callora.webhook_deliveries using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.connector_accounts enable row level security; alter table callora.connector_accounts force row level security; create policy connector_accounts_tenant on callora.connector_accounts using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.connector_runs enable row level security; alter table callora.connector_runs force row level security; create policy connector_runs_tenant on callora.connector_runs using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.subscriptions enable row level security; alter table callora.subscriptions force row level security; create policy subscriptions_tenant on callora.subscriptions using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.billing_events enable row level security; alter table callora.billing_events force row level security; create policy billing_events_tenant on callora.billing_events using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
alter table callora.invoices enable row level security; alter table callora.invoices force row level security; create policy invoices_tenant on callora.invoices using(organization_id=callora.current_organization_id()) with check(organization_id=callora.current_organization_id());
commit;
